{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "SkillsTreeOutput",
  "description": "Schema for a 3-level NGSS-aligned skills tree: superskill → skills → subskills.",
  "type": "object",
  "additionalProperties": false,

  "properties": {
    "superskill": {
      "type": "string",
      "minLength": 5,
      "description": "A single overarching learning goal summarizing the full standards progression."
    },

    "skills": {
      "type": "array",
      "minItems": 1,
      "description": "List of major skills derived from the superskill.",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["skill", "subskills"],

        "properties": {
          "skill": {
            "type": "string",
            "minLength": 5,
            "description": "A major conceptual or procedural skill."
          },

          "subskills": {
            "type": "array",
            "minItems": 1,
            "description": "List of observable, teachable subskills for this skill.",
            "items": {
              "type": "string",
              "minLength": 5
            }
          }
        }
      }
    }
  },

  "required": ["superskill", "skills"]
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "InstructionalContentOutput",
  "type": "object",
  "required": ["metadata", "main_content", "assessments", "visual_models"],
  "additionalProperties": false,

  "properties": {
    "metadata": {
      "type": "object",
      "required": ["standard_id", "grade_band", "cognitive_depth", "superskill"],
      "additionalProperties": false,
      "properties": {
        "standard_id": { "type": "string" },
        "grade_band": { "type": "string" },
        "cognitive_depth": { "type": "string" },
        "superskill": { "type": "string" }
      }
    },

    "main_content": {
      "type": "object",
      "minProperties": 1,
      "additionalProperties": false,
      "patternProperties": {
        "^topic_[0-9]+$": {
          "type": "object",
          "required": ["title", "description", "subtopics"],
          "additionalProperties": false,
          "properties": {
            "title": { "type": "string" },
            "description": { "type": "string" },
            "subtopics": {
              "type": "array",
              "minItems": 1,
              "items": {
                "type": "object",
                "required": ["subskill", "details"],
                "additionalProperties": false,
                "properties": {
                  "subskill": { "type": "string" },
                  "details": { "type": "string" }
                }
              }
            }
          }
        }
      }
    },

    "assessments": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "type",
          "question",
          "subskill_reference",
          "correct_response"
        ],
        "additionalProperties": false,

        "properties": {
          "type": {
            "type": "string",
            "enum": [
              "MULTIPLE_CHOICE",
              "SHORT_ANSWER",
              "TRUE_FALSE_WITH_CORRECTION",
              "FILL_IN_THE_BLANK",
              "MATCHING"
            ]
          },

          "question": { "type": "string" },
          "subskill_reference": { "type": "string" },

          "correct_response": { "type": "string" },

          "options": {
            "type": "array",
            "items": { "type": "string" }
          }
        }
      }
    },

    "visual_models": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "model_title",
          "description",
          "reasoning_purpose",
          "scale_representation"
        ],
        "additionalProperties": false,
        "properties": {
          "model_title": { "type": "string" },
          "description": { "type": "string" },
          "reasoning_purpose": { "type": "string" },
          "scale_representation": { "type": "string" }
        }
      }
    }
  }
}
